
"use client";

import { useState, useEffect, useRef } from "react";
import { Html5Qrcode } from "html5-qrcode";
import { Button } from "@/components/ui/button";
import { X, Smartphone } from "lucide-react";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { toast } from "sonner";

interface BarcodeScannerProps {
  onScan: (decodedText: string) => void;
  onCancel: () => void;
}

export default function BarcodeScanner({ onScan, onCancel }: BarcodeScannerProps) {
  const [hasCameraPermission, setHasCameraPermission] = useState<boolean | null>(null);
  const scannerRef = useRef<Html5Qrcode | null>(null);
  const readerId = `qr-reader-${Math.random().toString(36).substring(2, 9)}`;

  // Handle scanner cleanup on unmount
  useEffect(() => {
    return () => {
      if (scannerRef.current && scannerRef.current.isScanning) {
        scannerRef.current.stop().catch(console.error);
      }
    };
  }, []);

  // Initialize and start scanner once the component mounts
  useEffect(() => {
    let isMounted = true;
    
    const startScanner = async () => {
        await new Promise(resolve => setTimeout(resolve, 100)); // Ensure DOM is ready
        if (!isMounted) return;

        try {
            const element = document.getElementById(readerId);
            if (!element) throw new Error("Scanner element not found");

            const html5QrCode = new Html5Qrcode(readerId);
            scannerRef.current = html5QrCode;

            await html5QrCode.start(
                { facingMode: "environment" },
                { fps: 10, qrbox: { width: 300, height: 150 } },
                (decodedText) => {
                    onScan(decodedText);
                    toast.success("Barcode Captured");
                },
                () => {}
            );
            
            setHasCameraPermission(true);
            toast.info("Camera Active: Align barcode in frame");
        } catch (err) {
            console.error("Scanner error:", err);
            setHasCameraPermission(false);
            onCancel(); // Close if camera fails
            toast.error("Camera Access Denied or Busy");
        }
    };

    startScanner();

    return () => { isMounted = false; };
  }, []);

  const stopScan = async () => {
    if (scannerRef.current && scannerRef.current.isScanning) {
      try {
        await scannerRef.current.stop();
      } catch (err) {
        console.error("Stop error:", err);
      }
    }
    onCancel();
  };

  return (
    <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4 animate-in fade-in">
        <div className="bg-white p-6 rounded-2xl shadow-2xl w-full max-w-md relative">
            <div 
                id={readerId} 
                className="w-full rounded-lg overflow-hidden border bg-black shadow-inner aspect-[4/3]"
            ></div>
             <Button 
                onClick={stopScan} 
                size="icon"
                className="absolute -top-4 -right-4 bg-primary text-white rounded-full shadow-lg border-4 border-white h-12 w-12 z-10"
            >
                <X className="h-6 w-6" />
            </Button>
            <div className="text-center mt-4">
                <p className="font-bold">Scanning Barcode...</p>
                <p className="text-sm text-gray-500">Position the barcode within the frame</p>
            </div>
             {hasCameraPermission === false && (
                <Alert variant="destructive" className="mt-4">
                <AlertTitle>Camera Permission Denied</AlertTitle>
                <AlertDescription>
                    Please allow camera access in your browser settings to use the scanner.
                </AlertDescription>
                </Alert>
            )}
        </div>
    </div>
  );
}
